refsection.programlisting:
rand("seed", 0)
x = ["a"; "b"; "b"; "c"; "a"];
x1 = floor(rand(5,1)*5)-1.5;
x2 = -floor(rand(5,1)*5)+0.5;
t = table(x, x1, x2, "VariableNames", ["x", "x1", "x2"]);
parquetWrite(fullfile(TMPDIR, "table.parquet"), t);
t2 = parquetRead(fullfile(TMPDIR, "table.parquet"))
// t2 = [5x3 table]
//
//    x     x1     x2 
//   ___   ____   ____
//                    
//   a     -0.5   -2.5
//   b     1.5    -3.5
//   b     -1.5   -2.5
//   c     -0.5   -3.5
//   a     1.5    0.5
